  spend(
    datum: Option<WithdrawDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let cred: Credential = ScriptCredential(d.required_script_hash)
        pairs.has_key(self.withdrawals, cred)
      }
    }
  }
}

use aiken/collection/pairs
use cardano/address.{Credential, ScriptCredential}
use cardano/transaction.{Transaction, OutputReference}

pub type WithdrawDatum {
  script_hash: ByteArray,
  min_amount: Int,
}

validator min_withdrawal_validator {
  spend(
    datum: Option<WithdrawDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let cred: Credential = ScriptCredential(d.script_hash)
        when pairs.get_first(self.withdrawals, cred) is {
          None -> False
          Some(amount) -> amount >= d.min_amount
        }
      }
    }
  }
}
